//! V8.0 S3 — `groebner_basis(polys, vars [, order])` Maxima builtin.
//!
//! Wires `maxima_poly::buchberger` through to the Maxima surface. Returns a
//! list of polynomials forming the reduced Gröbner basis of the ideal
//! generated by `polys` under the chosen monomial order (default Grevlex).

use maxima_core::{Expr, Operator, SymbolId, resolve};
use maxima_poly::{buchberger, expr_to_mpoly, mpoly_to_expr, MonomialOrder};

pub(crate) fn eval_groebner(name: &str, args: &[Expr]) -> Option<Expr> {
    match name {
        "groebner_basis" => Some(eval_groebner_basis(args)),
        "eliminate" => Some(eval_eliminate(args)),
        "ideal_sum" => Some(eval_ideal_sum(args)),
        "ideal_product" => Some(eval_ideal_product(args)),
        "ideal_intersect" => Some(eval_ideal_intersect(args)),
        "ideal_contains" => Some(eval_ideal_contains(args)),
        _ => None,
    }
}

/// `factor_multivariate(p)` — minimal multivariate factor (S7).
///
/// Goal: improve on the existing `factor`, which returns multivariate input
/// untouched. We don't ship a full Hensel-lifting factoriser (deferred to
/// V9.0 per the V8.0 plan); but two cheap, useful steps cover a lot:
/// extract the monomial-GCD of all terms as a common factor, and if what
/// remains is univariate, pass it through the existing `factor`.
pub(crate) fn eval_factor_multivariate(args: &[Expr], env: &mut crate::env::Environment) -> Expr {
    use maxima_poly::{expr_to_mpoly, mpoly_to_expr, MCoeff, MonomialOrder, MPoly, Monomial};
    use num::One;

    let noun = || Expr::call("factor_multivariate", args.to_vec());
    if args.is_empty() { return noun(); }
    let poly_expr = &args[0];

    // Collect symbols to form the variable list.
    let mut vars: Vec<SymbolId> = Vec::new();
    collect_symbols(poly_expr, &mut vars);
    if vars.is_empty() {
        // Nothing variable in the input — return as is.
        return poly_expr.clone();
    }
    let p = match expr_to_mpoly(poly_expr, &vars, MonomialOrder::Grevlex) {
        Some(p) => p,
        None => return noun(),
    };
    if p.is_zero() { return Expr::int(0); }

    // 1. Monomial GCD across every term.
    let mut common = p.terms[0].0.clone();
    for (m, _) in &p.terms[1..] {
        for i in 0..common.0.len() {
            common.0[i] = common.0[i].min(m.0[i]);
        }
    }

    let mut factored = p.clone();
    if !common.is_one() {
        // Divide every term by `common`.
        factored.terms = p.terms.iter().map(|(m, c)| {
            let new_m = Monomial::div(m, &common).expect("min divides each");
            (new_m, c.clone())
        }).collect();
    }

    // 2. If the remaining polynomial is univariate (only one variable has any
    //    positive exponent across all terms), defer to the host's `factor`.
    let mut used_var: Option<usize> = None;
    let mut multi = false;
    for (m, _) in &factored.terms {
        for (i, &e) in m.0.iter().enumerate() {
            if e > 0 {
                match used_var {
                    None => used_var = Some(i),
                    Some(v) if v == i => {}
                    Some(_) => { multi = true; break; }
                }
            }
        }
        if multi { break; }
    }

    let factored_expr = mpoly_to_expr(&factored);
    let inner = if !multi && used_var.is_some() {
        // Pass to the existing univariate factor.
        crate::eval::meval(&Expr::call("factor", vec![factored_expr]), env)
    } else {
        factored_expr
    };

    // 3. Reassemble: common_monomial * inner.
    if common.is_one() {
        inner
    } else {
        let common_expr = monomial_to_expr(&common, &vars);
        // Multiply: c_mono * inner.  Wrap in MTimes; let the host simplifier
        // sort it out.
        Expr::List { op: Operator::MTimes, simplified: false, args: vec![common_expr, inner] }
    }
}

fn monomial_to_expr(m: &maxima_poly::Monomial, vars: &[SymbolId]) -> Expr {
    let mut factors: Vec<Expr> = Vec::new();
    for (i, &e) in m.0.iter().enumerate() {
        if e == 0 { continue; }
        let sym = Expr::Symbol(vars[i]);
        if e == 1 { factors.push(sym); }
        else { factors.push(Expr::pow(sym, Expr::int(e as i64))); }
    }
    match factors.len() {
        0 => Expr::int(1),
        1 => factors.pop().unwrap(),
        _ => Expr::List { op: Operator::MTimes, simplified: false, args: factors },
    }
}

/// `ideal_sum([I_gens], [J_gens], [vars])`: a reduced Gröbner basis for `I + J`,
/// computed from the union of generators.
fn eval_ideal_sum(args: &[Expr]) -> Expr {
    use maxima_poly::{buchberger, expr_to_mpoly, mpoly_to_expr, MonomialOrder};
    let noun = || Expr::call("ideal_sum", args.to_vec());
    if args.len() != 3 { return noun(); }
    let gens_i = match extract_list(&args[0]) { Some(l) => l, None => return noun() };
    let gens_j = match extract_list(&args[1]) { Some(l) => l, None => return noun() };
    let vars = match extract_vars(&args[2]) { Some(v) => v, None => return noun() };

    let mut all: Vec<_> = Vec::with_capacity(gens_i.len() + gens_j.len());
    for p in gens_i.iter().chain(gens_j.iter()) {
        let p = equation_to_polynomial(p.clone());
        match expr_to_mpoly(&p, &vars, MonomialOrder::Grevlex) {
            Some(m) => all.push(m),
            None => return noun(),
        }
    }
    let basis = buchberger(&all);
    Expr::list(basis.iter().map(mpoly_to_expr).collect())
}

/// `ideal_product([I_gens], [J_gens], [vars])`: generators of `I · J` are
/// the pairwise products `g_i · h_j`.
fn eval_ideal_product(args: &[Expr]) -> Expr {
    use maxima_poly::{buchberger, expr_to_mpoly, mpoly_to_expr, MonomialOrder, MPoly};
    let noun = || Expr::call("ideal_product", args.to_vec());
    if args.len() != 3 { return noun(); }
    let gens_i = match extract_list(&args[0]) { Some(l) => l, None => return noun() };
    let gens_j = match extract_list(&args[1]) { Some(l) => l, None => return noun() };
    let vars = match extract_vars(&args[2]) { Some(v) => v, None => return noun() };

    let parse = |e: &Expr| -> Option<MPoly> {
        let e = equation_to_polynomial(e.clone());
        expr_to_mpoly(&e, &vars, MonomialOrder::Grevlex)
    };
    let polys_i: Option<Vec<MPoly>> = gens_i.iter().map(parse).collect();
    let polys_j: Option<Vec<MPoly>> = gens_j.iter().map(parse).collect();
    let (polys_i, polys_j) = match (polys_i, polys_j) {
        (Some(a), Some(b)) => (a, b),
        _ => return noun(),
    };

    let mut prods = Vec::with_capacity(polys_i.len() * polys_j.len());
    for a in &polys_i { for b in &polys_j { prods.push(a.mul(b)); } }
    let basis = buchberger(&prods);
    Expr::list(basis.iter().map(mpoly_to_expr).collect())
}

/// `ideal_intersect([I_gens], [J_gens], [vars])`: textbook trick — introduce a
/// fresh variable `%t`, take `t·I + (1-t)·J` in the larger ring, and the
/// elimination of `t` is the intersection.
fn eval_ideal_intersect(args: &[Expr]) -> Expr {
    use maxima_poly::{buchberger, expr_to_mpoly, mpoly_to_expr, MonomialOrder, MPoly};
    let noun = || Expr::call("ideal_intersect", args.to_vec());
    if args.len() != 3 { return noun(); }
    let gens_i = match extract_list(&args[0]) { Some(l) => l, None => return noun() };
    let gens_j = match extract_list(&args[1]) { Some(l) => l, None => return noun() };
    let vars = match extract_vars(&args[2]) { Some(v) => v, None => return noun() };

    // Fresh "t" variable — name unlikely to collide with the user's symbols.
    let t_sym = maxima_core::intern("%intersect_t");
    let mut extended_vars = vec![t_sym];
    extended_vars.extend_from_slice(&vars);

    let t_expr = Expr::Symbol(t_sym);
    // generators: t·f for f in I_gens, and (1 - t)·g for g in J_gens
    let mut combined: Vec<MPoly> = Vec::new();
    for f in gens_i {
        let f = equation_to_polynomial(f.clone());
        let prod = Expr::mul(t_expr.clone(), f);
        match expr_to_mpoly(&prod, &extended_vars, MonomialOrder::Lex) {
            Some(m) => combined.push(m),
            None => return noun(),
        }
    }
    let one_minus_t = Expr::sub(Expr::int(1), t_expr);
    for g in gens_j {
        let g = equation_to_polynomial(g.clone());
        let prod = Expr::mul(one_minus_t.clone(), g);
        match expr_to_mpoly(&prod, &extended_vars, MonomialOrder::Lex) {
            Some(m) => combined.push(m),
            None => return noun(),
        }
    }
    let basis = buchberger(&combined);

    // Keep only elements that don't involve t — those generate the intersection.
    let kept: Vec<Expr> = basis.iter()
        .filter(|p| p.terms.iter().all(|(m, _)| m.0[0] == 0))
        .map(mpoly_to_expr)
        .collect();
    Expr::list(kept)
}

/// `ideal_contains(p, [generators], [vars])` — true iff `p` lies in the ideal.
fn eval_ideal_contains(args: &[Expr]) -> Expr {
    use maxima_poly::{buchberger, expr_to_mpoly, normal_form, MonomialOrder, MPoly};
    let noun = || Expr::call("ideal_contains", args.to_vec());
    if args.len() != 3 { return noun(); }
    let p_raw = equation_to_polynomial(args[0].clone());
    let gens = match extract_list(&args[1]) { Some(l) => l, None => return noun() };
    let vars = match extract_vars(&args[2]) { Some(v) => v, None => return noun() };

    let p = match expr_to_mpoly(&p_raw, &vars, MonomialOrder::Grevlex) {
        Some(m) => m,
        None => return noun(),
    };
    let mut input_polys: Vec<MPoly> = Vec::with_capacity(gens.len());
    for g in gens {
        let g = equation_to_polynomial(g.clone());
        match expr_to_mpoly(&g, &vars, MonomialOrder::Grevlex) {
            Some(m) => input_polys.push(m),
            None => return noun(),
        }
    }
    let basis = buchberger(&input_polys);
    let r = normal_form(&p, &basis);
    if r.is_zero() { Expr::sym("true") } else { Expr::sym("false") }
}

fn collect_symbols(e: &Expr, out: &mut Vec<SymbolId>) {
    match e {
        Expr::Symbol(id) => {
            if !out.contains(id) { out.push(*id); }
        }
        Expr::List { args, .. } => {
            for a in args { collect_symbols(a, out); }
        }
        _ => {}
    }
}

/// `eliminate(polys, vars_to_eliminate)` — compute the elimination ideal.
///
/// Idea: under lex order with eliminated variables first, the elements of
/// the reduced Gröbner basis that involve only the *remaining* variables
/// generate the ideal of all algebraic consequences in those variables.
/// Used for variety projection and parametric → implicit conversion.
fn eval_eliminate(args: &[Expr]) -> Expr {
    use maxima_poly::{buchberger, expr_to_mpoly, mpoly_to_expr, MPoly, MonomialOrder};

    let noun = || Expr::call("eliminate", args.to_vec());
    if args.len() != 2 { return noun(); }

    let polys_raw = match extract_list(&args[0]) { Some(l) => l.to_vec(), None => return noun() };
    let eliminated = match extract_vars(&args[1]) { Some(v) => v, None => return noun() };
    if eliminated.is_empty() {
        return Expr::list(polys_raw);
    }
    // Accept p = q in addition to bare polynomials.
    let polys_list: Vec<Expr> = polys_raw.into_iter().map(equation_to_polynomial).collect();

    let mut all_syms: Vec<SymbolId> = Vec::new();
    for p in &polys_list { collect_symbols(p, &mut all_syms); }

    // Variable order: eliminated first (highest under lex), then the rest.
    let mut remaining: Vec<SymbolId> = all_syms.iter()
        .filter(|s| !eliminated.contains(s))
        .copied()
        .collect();
    if remaining.is_empty() {
        // All variables are being eliminated — result is whatever univariate
        // / constant relations live in the basis. Compute and return all.
    }
    let mut vars = eliminated.clone();
    vars.append(&mut remaining);
    let elim_count = eliminated.len();

    // Build the MPoly inputs.
    let mut mpolys: Vec<MPoly> = Vec::with_capacity(polys_list.len());
    for p in &polys_list {
        match expr_to_mpoly(p, &vars, MonomialOrder::Lex) {
            Some(m) => mpolys.push(m),
            None => return noun(),
        }
    }
    let basis = buchberger(&mpolys);

    // Keep only basis elements involving none of the eliminated variables —
    // those are the elements of the elimination ideal.
    let kept: Vec<Expr> = basis.iter()
        .filter(|p| {
            p.terms.iter().all(|(m, _)| {
                (0..elim_count).all(|i| m.0[i] == 0)
            })
        })
        .map(mpoly_to_expr)
        .collect();
    Expr::list(kept)
}

/// `polysys_solve(eqns, vars)` — solve a zero-dimensional polynomial system
/// via lex Gröbner triangulation. Entry point used by the host evaluator.
pub(crate) fn eval_polysys_solve(args: &[Expr], env: &mut crate::env::Environment) -> Expr {
    let noun = || Expr::call("polysys_solve", args.to_vec());
    if args.len() != 2 { return noun(); }

    let polys_list = match extract_list(&args[0]) { Some(l) => l.to_vec(), None => return noun() };
    let vars = match extract_vars(&args[1]) { Some(v) => v, None => return noun() };
    if vars.is_empty() { return noun(); }

    // For each input polynomial, accept either `p = 0` (Maxima equation form)
    // or just `p` (already-zeroed). Both end up as the polynomial itself.
    let polys: Vec<Expr> = polys_list.into_iter().map(equation_to_polynomial).collect();

    match polysys_solve_recursive(&polys, &vars, env) {
        Some(list) => list,
        None => noun(),
    }
}

fn equation_to_polynomial(e: Expr) -> Expr {
    if let Expr::List { op: Operator::MEqual, args, .. } = &e {
        if args.len() == 2 {
            // p = q  →  p - q
            return Expr::sub(args[0].clone(), args[1].clone());
        }
    }
    e
}

/// Triangulation cascade. Returns `Some(list_of_solutions)` if the system
/// triangulates cleanly under lex; `None` if it doesn't (return noun upstream).
fn polysys_solve_recursive(
    polys: &[Expr],
    vars: &[SymbolId],
    env: &mut crate::env::Environment,
) -> Option<Expr> {
    use maxima_poly::{buchberger, expr_to_mpoly, mpoly_to_expr, MPoly, MonomialOrder};

    // 1. Compute lex Gröbner basis.
    let mut mpolys: Vec<MPoly> = Vec::with_capacity(polys.len());
    for p in polys {
        mpolys.push(expr_to_mpoly(p, vars, MonomialOrder::Lex)?);
    }
    // Drop zero polynomials.
    mpolys.retain(|p| !p.is_zero());
    if mpolys.is_empty() {
        // 0 = 0 only: any value works.  Return one empty solution.
        return Some(Expr::list(vec![Expr::list(vec![])]));
    }
    let basis = buchberger(&mpolys);

    // 2. Constant in basis → no solutions.
    if basis.iter().any(|p| p.terms.len() == 1 && p.terms[0].0.is_one()) {
        return Some(Expr::list(vec![]));
    }

    // 3. Find an element involving only the LAST variable.
    let last_idx = vars.len() - 1;
    let univariate = basis.iter().find(|p| {
        p.terms.iter().all(|(m, _)| {
            m.0.iter().enumerate().all(|(i, &e)| i == last_idx || e == 0)
        })
    })?;

    // 4. Solve the univariate via the host `solve`.
    let last_var = vars[last_idx];
    let uni_expr = mpoly_to_expr(univariate);
    let solve_call = Expr::call(
        "solve",
        vec![uni_expr, Expr::Symbol(last_var)],
    );
    let solutions = crate::eval::meval(&solve_call, env);
    let sol_items = match solutions {
        Expr::List { op: Operator::MList, args, .. } => args,
        _ => return None,
    };

    // 5. Base case: only one variable left.
    if vars.len() == 1 {
        return Some(Expr::list(
            sol_items.into_iter().map(|eq| Expr::list(vec![eq])).collect(),
        ));
    }

    // 6. Recurse for each root, substituting the value and dropping the
    //    univariate from the system.
    let smaller_vars: Vec<SymbolId> = vars[..last_idx].to_vec();
    let mut all_solutions = Vec::new();

    for sol_eq in sol_items {
        let value = match &sol_eq {
            Expr::List { op: Operator::MEqual, args, .. } if args.len() == 2 => args[1].clone(),
            _ => continue,
        };
        let other_polys: Vec<Expr> = basis.iter()
            .filter(|p| !std::ptr::eq(*p, univariate))
            .map(|p| {
                let e = mpoly_to_expr(p);
                crate::eval::meval(
                    &Expr::call("subst", vec![value.clone(), Expr::Symbol(last_var), e]),
                    env,
                )
            })
            .collect();
        let sub = polysys_solve_recursive(&other_polys, &smaller_vars, env)?;
        if let Expr::List { op: Operator::MList, args, .. } = sub {
            for ss in args {
                if let Expr::List { op: Operator::MList, args: mut s_args, .. } = ss {
                    // Append this variable's binding to the inner solution.
                    s_args.push(sol_eq.clone());
                    all_solutions.push(Expr::list(s_args));
                }
            }
        }
    }
    Some(Expr::list(all_solutions))
}

fn parse_order(arg: &Expr) -> Option<MonomialOrder> {
    let name = match arg {
        Expr::Symbol(id) => resolve(*id),
        Expr::String(s) => s.to_string(),
        _ => return None,
    };
    match name.as_str() {
        "lex" => Some(MonomialOrder::Lex),
        "grlex" => Some(MonomialOrder::Grlex),
        "grevlex" => Some(MonomialOrder::Grevlex),
        _ => None,
    }
}

fn extract_list(e: &Expr) -> Option<&[Expr]> {
    if let Expr::List { op: Operator::MList, args, .. } = e {
        Some(args)
    } else {
        None
    }
}

fn extract_vars(e: &Expr) -> Option<Vec<SymbolId>> {
    let items = extract_list(e)?;
    let mut out = Vec::with_capacity(items.len());
    for v in items {
        if let Expr::Symbol(id) = v {
            out.push(*id);
        } else {
            return None;
        }
    }
    Some(out)
}

fn eval_groebner_basis(args: &[Expr]) -> Expr {
    // Accept 2 or 3 args: (polys, vars), or (polys, vars, order).
    if args.len() != 2 && args.len() != 3 {
        return Expr::call("groebner_basis", args.to_vec());
    }
    let noun = || Expr::call("groebner_basis", args.to_vec());

    let polys_list = match extract_list(&args[0]) { Some(l) => l, None => return noun() };
    let vars = match extract_vars(&args[1]) { Some(v) => v, None => return noun() };
    if vars.is_empty() { return noun(); }
    let order = if args.len() == 3 {
        match parse_order(&args[2]) { Some(o) => o, None => return noun() }
    } else {
        MonomialOrder::Grevlex
    };

    let mut inputs = Vec::with_capacity(polys_list.len());
    for p in polys_list {
        match expr_to_mpoly(p, &vars, order) {
            Some(m) => inputs.push(m),
            None => return noun(), // non-polynomial input — be explicit, not silent.
        }
    }
    let basis = buchberger(&inputs);
    let items: Vec<Expr> = basis.iter().map(mpoly_to_expr).collect();
    Expr::list(items)
}
